SELECT
count(1)
from user_registration_info a


        AND a.registration_time  >=  #{vo.startRegistrationTime}


        AND a.registration_time  <=  #{vo.endRegistrationTime}


        AND a.member_type IN

            #{value}



        AND a.register_terminal IN

            #{value}



        AND a.member_id = #{vo.memberId}


        AND a.superior_agent = #{vo.superiorAgent}


        AND a.register_ip = #{vo.registerIp}


        AND a.ip_attribution = #{vo.ipAttribution}


        AND a.member_account = #{vo.memberAccount}


        AND a.site_code = #{vo.siteCode}


        AND a.email = #{vo.email}


        AND a.phone = #{vo.phone}

SELECT
    a.registration_time as registrationTime,
    a.member_id as memberId,
    a.member_type as memberType,
    a.main_currency as mainCurrency,
    a.superior_agent as superiorAgent,
    a.member_account as memberAccount,
    a.register_ip as registerIp,
    a.ip_attribution as ipAttribution,
    a.register_terminal as registerTerminal,
    a.terminal_device_number as terminalDeviceNumber,
    b.phone as phone,
    b.area_code as areaCode,
    b.area_code as areaCode_$_phone,
    b.email as email,
    a.site_code as siteCode,
   a.agent_id as agentId
FROM user_registration_info a
left join user_info b on a.member_id = b.user_id


        AND a.registration_time  >=  #{vo.startRegistrationTime}


        AND a.registration_time  <=  #{vo.endRegistrationTime}


        AND a.superior_agent is not null


        AND a.superior_agent  null


        AND a.member_type IN

            #{value}



        AND a.register_terminal IN

            #{value}



        AND a.member_type = #{vo.accountType}


        AND a.member_id =  #{vo.memberId}


        AND a.superior_agent = #{vo.superiorAgent}


        AND a.register_ip =  #{vo.registerIp}


        AND a.ip_attribution =  #{vo.ipAttribution}


        AND a.member_account =  #{vo.memberAccount}


        AND a.site_code =  #{vo.siteCode}


        AND b.email =  #{vo.email}


        AND b.phone LIKE CONCAT('%', #{vo.phone},'%')




        ORDER BY ${vo.orderField} ${vo.orderType}


        ORDER BY a.registration_time DESC
